export interface ImageGenerationRequest {
    prompt: string;
    negativePrompt?: string;
    size?: string;
    quality?: string;
    style?: string;
    n?: number;
}

export interface ImageGenerationResult {
    id: string;
    prompt: string;
    url: string;
    revisedPrompt?: string;
    createdAt: number;
    provider: string;
    localPath?: string;
}

export interface ImageHistory {
    images: ImageGenerationResult[];
    total: number;
}

export class ImageSystem {
    private engine: unknown;
    private isInitialized: boolean = false;
    private history: ImageGenerationResult[] = [];
    private config = {
        provider: 'openai',
        endpoint: 'https://api.openai.com/v1/images/generations',
        apiKey: '',
        model: 'dall-e-3',
        size: '1024x1024',
        quality: 'standard'
    };

    constructor(engine: unknown) {
        this.engine = engine;
    }

    async init(): Promise<void> {
        if (this.isInitialized) return;

        console.log('[ImageSystem] 初始化图片生成系统...');

        this.loadConfig();
        this.loadHistory();

        this.isInitialized = true;
        console.log('[ImageSystem] 图片生成系统初始化完成');
    }

    private loadConfig(): void {
        const saved = localStorage.getItem('image_config');
        if (saved) {
            try {
                Object.assign(this.config, JSON.parse(saved));
            } catch (e) {
                console.error('[ImageSystem] 加载配置失败:', e);
            }
        }
    }

    private saveConfig(): void {
        localStorage.setItem('image_config', JSON.stringify(this.config));
    }

    private loadHistory(): void {
        const saved = localStorage.getItem('image_history');
        if (saved) {
            try {
                this.history = JSON.parse(saved);
            } catch (e) {
                console.error('[ImageSystem] 加载历史失败:', e);
            }
        }
    }

    private saveHistory(): void {
        localStorage.setItem('image_history', JSON.stringify(this.history));
    }

    configure(config: Partial<typeof this.config>): void {
        Object.assign(this.config, config);
        this.saveConfig();
    }

    getConfig(): typeof this.config {
        return { ...this.config };
    }

    async generate(request: ImageGenerationRequest): Promise<ImageGenerationResult> {
        if (!this.config.apiKey) {
            return this.generatePlaceholder(request);
        }

        try {
            const response = await fetch(this.config.endpoint, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${this.config.apiKey}`
                },
                body: JSON.stringify({
                    model: this.config.model,
                    prompt: request.prompt,
                    size: request.size || this.config.size,
                    quality: request.quality || this.config.quality,
                    n: request.n || 1,
                    style: request.style
                })
            });

            if (!response.ok) {
                const error = await response.json().catch(() => ({}));
                throw new Error(error.error?.message || `生成失败: ${response.status}`);
            }

            const data = await response.json();
            const imageData = data.data[0];

            const result: ImageGenerationResult = {
                id: `img_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
                prompt: request.prompt,
                url: imageData.url,
                revisedPrompt: imageData.revised_prompt,
                createdAt: Date.now(),
                provider: this.config.provider
            };

            this.history.unshift(result);
            if (this.history.length > 100) {
                this.history = this.history.slice(0, 100);
            }
            this.saveHistory();

            return result;
        } catch (error) {
            console.error('[ImageSystem] 生成图片失败:', error);
            return this.generatePlaceholder(request);
        }
    }

    private generatePlaceholder(request: ImageGenerationRequest): ImageGenerationResult {
        const result: ImageGenerationResult = {
            id: `img_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            prompt: request.prompt,
            url: this.generatePlaceholderImage(request.prompt),
            createdAt: Date.now(),
            provider: 'placeholder'
        };

        this.history.unshift(result);
        this.saveHistory();

        return result;
    }

    private generatePlaceholderImage(prompt: string): string {
        const canvas = document.createElement('canvas');
        canvas.width = 512;
        canvas.height = 512;
        const ctx = canvas.getContext('2d');

        if (ctx) {
            const gradient = ctx.createLinearGradient(0, 0, 512, 512);
            gradient.addColorStop(0, '#6366f1');
            gradient.addColorStop(0.5, '#ec4899');
            gradient.addColorStop(1, '#f59e0b');
            ctx.fillStyle = gradient;
            ctx.fillRect(0, 0, 512, 512);

            ctx.fillStyle = 'rgba(0, 0, 0, 0.3)';
            ctx.fillRect(0, 0, 512, 512);

            ctx.fillStyle = '#ffffff';
            ctx.font = 'bold 24px "Noto Sans SC", sans-serif';
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';

            const words = prompt.split(' ');
            let lines: string[] = [];
            let currentLine = '';

            words.forEach(word => {
                const testLine = currentLine + word + ' ';
                if (testLine.length > 20) {
                    lines.push(currentLine.trim());
                    currentLine = word + ' ';
                } else {
                    currentLine = testLine;
                }
            });
            if (currentLine.trim()) {
                lines.push(currentLine.trim());
            }

            lines = lines.slice(0, 5);
            const lineHeight = 30;
            const startY = 256 - (lines.length * lineHeight) / 2;

            lines.forEach((line, i) => {
                ctx.fillText(line, 256, startY + i * lineHeight);
            });

            ctx.font = '14px "Noto Sans SC", sans-serif';
            ctx.fillStyle = 'rgba(255, 255, 255, 0.7)';
            ctx.fillText('请配置API密钥以生成真实图片', 256, 480);
        }

        return canvas.toDataURL('image/png');
    }

    getHistory(): ImageGenerationResult[] {
        return [...this.history];
    }

    deleteImage(id: string): boolean {
        const index = this.history.findIndex(img => img.id === id);
        if (index > -1) {
            this.history.splice(index, 1);
            this.saveHistory();
            return true;
        }
        return false;
    }

    clearHistory(): void {
        this.history = [];
        this.saveHistory();
    }

    async downloadImage(imageUrl: string, filename?: string): Promise<void> {
        try {
            let url = imageUrl;
            let blob: Blob;

            if (imageUrl.startsWith('data:')) {
                const response = await fetch(imageUrl);
                blob = await response.blob();
            } else {
                const response = await fetch(imageUrl);
                blob = await response.blob();
            }

            url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = filename || `ai_image_${Date.now()}.png`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        } catch (error) {
            console.error('[ImageSystem] 下载图片失败:', error);
            throw error;
        }
    }

    async generateVariation(imageUrl: string): Promise<ImageGenerationResult> {
        const original = this.history.find(img => img.url === imageUrl);
        if (original) {
            return this.generate({
                prompt: original.revisedPrompt || original.prompt,
                size: this.config.size,
                quality: this.config.quality
            });
        }
        throw new Error('找不到原始图片');
    }

    getSizes(): Array<{ value: string; label: string }> {
        return [
            { value: '256x256', label: '256×256 (小)' },
            { value: '512x512', label: '512×512 (中)' },
            { value: '1024x1024', label: '1024×1024 (方)' },
            { value: '1792x1024', label: '1792×1024 (横)' },
            { value: '1024x1792', label: '1024×1792 (竖)' }
        ];
    }

    getQualities(): Array<{ value: string; label: string }> {
        return [
            { value: 'standard', label: '标准' },
            { value: 'hd', label: '高清' }
        ];
    }

    getStyles(): Array<{ value: string; label: string }> {
        return [
            { value: 'vivid', label: '生动' },
            { value: 'natural', label: '自然' }
        ];
    }
}

export default ImageSystem;
